function solve(c: number, connections: number[][], queries: number[][]): number[] {
    // Build the graph
    const graph: number[][] = Array(c + 1).fill(0).map(() => Array<number>());
    for (const [u, v] of connections) {
        graph[u].push(v);
        graph[v].push(u);
    }

    // For each node, keep track of its current parent in the DSU
    const parent: number[] = Array(c + 1).fill(0).map((_, i) => i);
    // For each node, keep track of the minimum id in its connected component
    const minId: number[] = Array(c + 1).fill(0).map((_, i) => i);

    // Find function with path compression
    function find(x: number): number {
        if (parent[x] !== x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    // Union function
    function union(x: number, y: number): void {
        const rootX = find(x);
        const rootY = find(y);
        if (rootX !== rootY) {
            parent[rootY] = rootX;
            minId[rootX] = Math.min(minId[rootX], minId[rootY]);
        }
    }

    // Initialize DSU
    for (let i = 1; i <= c; i++) {
        union(i, i);
    }

    // Process queries
    const result: number[] = [];
    const online: boolean[] = Array(c + 1).fill(true);

    for (const [type, x] of queries) {
        if (type === 1) {
            if (online[x]) {
                result.push(x);
            } else {
                const root = find(x);
                if (online[root]) {
                    result.push(minId[root]);
                } else {
                    result.push(-1);
                }
            }
        } else {
            online[x] = false;
        }
    }

    return result;
}

